// src/pages/admin/index.js

import React, { useEffect, useState } from 'react'
import AdminLayout from '../../components/AdminLayout'
import {  GetApprovedProfileCount, GetProfileCount, GetUnapprovedProfileCount } from '../../service/Profile.service'

const AdminPage = () => {
  const [counts, setCounts] = useState({})
  useEffect(()=>{
    ;(async()=>{
      const [totalCount, approvedcount, unapprovedcount] = await Promise.all([GetProfileCount(), GetApprovedProfileCount(), GetUnapprovedProfileCount()]);
      setCounts({
        totalCount: totalCount.data.getProfileCount,
        approvedcount: approvedcount.data.getApprovedProfileCount,
        unapprovedcount: unapprovedcount.data.getUnapprovedProfileCount
      })
    
    })();
  },[])
  return (
    <AdminLayout>
      <div>
        <h1 className='text-3xl font-bold mb-6'>Admin Dashboard</h1>
        <div className='grid grid-cols-1 md:grid-cols-3 gap-6'>
          {/* Admin Dashboard Widgets */}
          <div className='bg-white p-6 rounded-lg shadow-sm'>
            <h3 className='text-lg font-semibold mb-2'>Total Users</h3>
            <p className='text-3xl font-bold text-blue-600'>{counts?.totalCount ?? 0}</p>
          </div>
          <div className='bg-white p-6 rounded-lg shadow-sm'>
            <h3 className='text-lg font-semibold mb-2'>Approved User</h3>
            <p className='text-3xl font-bold text-green-600'>{counts?.approvedcount ?? 0}</p>
          </div>
          <div className='bg-white p-6 rounded-lg shadow-sm'>
            <h3 className='text-lg font-semibold mb-2'>Unapproved User</h3>
            <p className='text-3xl font-bold text-purple-600'>{counts?.unapprovedcount ?? 0}</p>
          </div>
        </div>
      </div>
    </AdminLayout>
  )
}

export default AdminPage